import numba.cuda as cuda
import numpy as np

# Constants must be global for Numba to determine shared memory size at compile time
TILES_SIZE = 32
RADIUS = 1
SHARED_SIZE = TILES_SIZE + 2 * RADIUS

@cuda.jit
def convolution_1d_shared(inp: np.ndarray, mask: np.ndarray, out: np.ndarray) -> None:
    """Apply a 1D convolution mask to the input array using shared memory.

    Handles halo/boundary loading efficiently.
    Mask size is assumed to be odd (2*RADIUS + 1).
    """
    s_data = cuda.shared.array(shape=(SHARED_SIZE,), dtype=np.float32)

    gid = cuda.grid(1)
    tid = cuda.threadIdx.x

    # Global index offsets
    # Load main data
    if gid < inp.size:
        s_data[tid + RADIUS] = inp[gid]
    else:
        s_data[tid + RADIUS] = 0.0

    # Load Halo (Left)
    if tid < RADIUS:
        if gid >= RADIUS:
            s_data[tid] = inp[gid - RADIUS]
        else:
            s_data[tid] = 0.0 # Zero padding at boundary

    # Load Halo (Right)
    if tid >= TILES_SIZE - RADIUS:
        if gid + RADIUS < inp.size:
            s_data[tid + 2 * RADIUS] = inp[gid + RADIUS]
        else:
            s_data[tid + 2 * RADIUS] = 0.0

    cuda.syncthreads()

    # Compute convolution
    if gid < out.size:
        temp_val = 0.0
        for i in range(2 * RADIUS + 1):
            temp_val += s_data[tid + i] * mask[i]
        out[gid] = temp_val
